const loadWorkoutData = async () => {
  if (!token || !id) return;

  try {
    setLoading(true);

    // Получаем данные тренировки
    const workout = await workoutsService.getWorkoutById(id, token);
    setWorkoutName(workout.name);

    // Получаем courseId из query параметров
    const params = new URLSearchParams(window.location.search);
    const courseId = params.get("courseId");

    let progressData: number[] = [];

    // Если есть courseId, получаем прогресс
    if (courseId) {
      try {
        const progress = await coursesService.getWorkoutProgress(
          courseId,
          id,
          token,
        );
        progressData = progress.progressData;
      } catch (err) {
        console.log("No progress found for this workout");
      }
    }

    const exercisesWithProgress = workout.exercises.map((ex, index) => ({
      ...ex,
      progress: progressData[index] || 0,
    }));

    setExercises(exercisesWithProgress);
  } catch (err) {
    setError(err instanceof Error ? err.message : "Ошибка загрузки тренировки");
  } finally {
    setLoading(false);
  }
};
